        self.calls: list[tuple[str, tuple, dict]] = []

    def __getattr__(self, method_name: str):
        def call(*args, **kwargs):
            self.calls.append((method_name, args, kwargs))
            return _Response(method_name)

        return call


class _Kiwoom:
